async function createDriver(dbPath) {
  if (typeof process.versions["bun"] !== "undefined") {
    const { BunSqliteDriver } = await Promise.resolve().then(() => require("./chunks/BunSqliteDriver-BYyigrms.js"));
    return new BunSqliteDriver(dbPath);
  }
  const { BetterSqlite3Driver } = await Promise.resolve().then(() => require("./chunks/BetterSqlite3Driver-E_RmGyC2.js"));
  return new BetterSqlite3Driver(dbPath);
}
